head.script:
scwin.chk = true;
scwin.wtEventChk = false;
scwin.qtyEventChk = false;
scwin.loUpperLobranCd = "";
scwin.hid_ctrtClntCd = "";
scwin.hid_ctrtClntNm = "";
scwin.hid_retrieveDmndListCd = "";
scwin.hid_retrieveDmndListNm = "";

scwin.onpageload = async function() {
    scwin.loUpperLobranCd = $c.ses.getLoUpperLobranCd() || "";
    scwin.f_OnLoad();
};

scwin.onUdcCompleted = async function() {
    let toDay = WebSquare.date.getCurrentServerDate("yyyyMMdd");
    udc_srchDate.setInitDate(toDay, toDay);
    lc_srchLobranCd.setValue(scwin.loUpperLobranCd);
};

scwin.f_OnLoad = async function() {
    sum_wt.setValue("0");
    scwin.f_vehclNrm();
};

scwin.f_Retrieve = async function() {
    if (!await $c.gus.cfValidate([ica_srchFromDate]) || !await $c.gus.cfValidate([ica_srchToDate])) {
        return;
    }

    if (!$c.gus.cfIsAfterDate(ica_srchFromDate.getValue(), ica_srchToDate.getValue())) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039);
        ica_srchFromDate.setFocus();
        return;
    }

    if (!await $c.gus.cfValidate([tb_srchCond])) {
        return;
    }

    scwin.f_ProcessBinding();
    $c.gus.cfShowDSWaitMsg(gr_transWrkPlan);
    await $c.sbm.execute(sbm_retrieve);
};

scwin.f_ProcessBinding = function() {
    dma_srchCond.set("lobranCd", lc_srchLobranCd.getValue());
    dma_srchCond.set("wrkDistrictCd1", lc_srchWrkDistrictCd1.getValue());
    dma_srchCond.set("wrkDistrictCd2", "");
    dma_srchCond.set("clntNo", ed_srchCtrtClntCd.getValue());
    dma_srchCond.set("cargoClsCd", "");
    dma_srchCond.set("wrkDstCd", "");
    dma_srchCond.set("stDt", ica_srchFromDate.getValue());
    dma_srchCond.set("endDt", ica_srchToDate.getValue());
    dma_srchCond.set("odrKndCd", lc_srchOdrKndCd.getValue());
    dma_srchCond.set("odrNo", ed_srchOdrNo.getValue());
    dma_srchCond.set("stWt", "");
    dma_srchCond.set("endWt", "");
    dma_srchCond.set("blNo", "");
    dma_srchCond.set("tplSaleClsCd", "");
    dma_srchCond.set("tplOrderClsCd", "");
    dma_srchCond.set("tplSelfClsCd", "");
    dma_srchCond.set("dmndNo", "");
    dma_srchCond.set("tplCoClsCd", "");
};

scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList;
    switch (disGubun) {
        case 1:
            udc_srchCtrtClnt.ilCommonPopUp(scwin.callbackCtrtClnt,
                pCode,
                pName,
                pClose,
                null,
                null,
                null,
                "3,4,5,6,7,8,9,10",
                ",5",
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null,
                null
            );
            break;
    }
};

scwin.callbackCtrtClnt = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_srchCtrtClntCd, txt_ctrtClntNm);
};

scwin.f_CheckCanDelete = async function() {
    let obj = ds_transWrkIndict;
    let vCount = 0;
    let vCoShipNo = "";
    let flag = false;

    for (let i = 0; i < obj.getRowCount(); i++) {
        vCount = 0;
        vCoShipNo = obj.getCellData(i, "coshippingNo");

        for (let j = 0; j < obj.getRowCount(); j++) {
            if (obj.getCellData(j, "coshippingNo") == vCoShipNo) {
                vCount++;

                if (obj.getRowStatus(j) == "D") {
                    vCount--;
                }
            }
        }

        if (vCount == 1) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["합적연결", "2건이상만 저장이나 삭제"]);
            flag = true;

            gr_transWrkIndict.setFocusedCell(i, "coshippingNo");
            break;
        }
    }

    return flag;
};

scwin.f_Delete = async function() {
    for (let j = ds_transWrkIndict.getRowCount() - 1; j >= 0; j--) {
        if (ds_transWrkIndict.getCellData(j, "chk") == "1" && ds_transWrkIndict.getRowStatus(j) != "D") {
            let row = j;

            if (ds_transWrkIndict.getCellData(row, "cstmrReqYn") == "1") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["고객요청에 의한 합적연결물량", "삭제"]);
            } else if (ds_transWrkIndict.getCellData(row, "transWrkIndictNo") != "") {
                await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["작업지시번호가 있는 물량", "삭제"]);
            } else {
                if (ds_transWrkIndict.getRowStatus(row) == "C") {
                    for (let i = 0; i < ds_transWrkPlan.getRowCount(); i++) {
                        if (ds_transWrkPlan.getCellData(i, "odrNo") == ds_transWrkIndict.getCellData(row, "odrNo") &&
                            ds_transWrkPlan.getCellData(i, "commSeq") == ds_transWrkIndict.getCellData(row, "commSeq") &&
                            ds_transWrkPlan.getCellData(i, "odrWrkPathSeq") == ds_transWrkIndict.getCellData(row, "odrWrkPathSeq") &&
                            ds_transWrkPlan.getCellData(i, "odrWrkStpSeq") == ds_transWrkIndict.getCellData(row, "odrWrkStpSeq")) {
                            scwin.qtyEventChk = true;
                            ds_transWrkPlan.setCellData(i, "oldQty", parseFloat(ds_transWrkPlan.getCellData(i, "oldQty")) + parseFloat(ds_transWrkIndict.getCellData(row, "qty")));
                            ds_transWrkPlan.setCellData(i, "qty", parseFloat(ds_transWrkPlan.getCellData(i, "qty")) + parseFloat(ds_transWrkIndict.getCellData(row, "qty")));
                            ds_transWrkPlan.setCellData(i, "oldGrossWt", parseFloat(ds_transWrkPlan.getCellData(i, "oldGrossWt")) + parseFloat(ds_transWrkIndict.getCellData(row, "grossWt")));
                            ds_transWrkPlan.setCellData(i, "grossWt", parseFloat(ds_transWrkPlan.getCellData(i, "grossWt")) + parseFloat(ds_transWrkIndict.getCellData(row, "grossWt")));
                            scwin.qtyEventChk = false;
                        }
                    }
                }

                ds_transWrkIndict.removeRow(row);
            }
        }
    }
};

scwin.f_Cancel = function() {
    ds_transWrkPlan.undoAll();
    ds_transWrkIndict.undoAll();
};

scwin.f_SaveCoshipping = async function() {
    if (ds_transWrkPlan.getRowCount() == 0 && ds_transWrkIndict.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_001, [""]);
        return;
    }

    if (ds_transWrkIndict.getUpdatedIndex().length > 0) {
    } else {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["연결물량"]);
        return;
    }

    let chkConfirm = await $c.win.confirm("저장하시겠습니까?");
    if (chkConfirm) {
        $c.gus.cfShowDSWaitMsg(gr_transWrkIndict);
        await $c.sbm.execute(sbm_save);
    }
};

scwin.f_checkValue = async function(row, colid) {
    if (colid == "qty" || colid == "grossWt" || colid == "netWt") {
        for (let i = 0; i < ds_copyTransWrkPlan.getRowCount(); i++) {
            if (ds_coshipping.getCellData(row, "odrNo") == ds_copyTransWrkPlan.getCellData(i, "odrNo")
                && parseInt(ds_coshipping.getCellData(row, "commSeq")) == parseInt(ds_copyTransWrkPlan.getCellData(i, "commSeq"))
                && parseInt(ds_coshipping.getCellData(row, "odrWrkPathSeq")) == parseInt(ds_copyTransWrkPlan.getCellData(i, "odrWrkPathSeq"))
                && parseInt(ds_coshipping.getCellData(row, "odrWrkStpSeq")) == parseInt(ds_copyTransWrkPlan.getCellData(i, "odrWrkStpSeq"))) {
                if (parseFloat(ds_coshipping.getCellData(row, colid)) > parseFloat(ds_copyTransWrkPlan.getCellData(i, colid))) {
                    await $c.gus.cfAlertMsg(MSG_CM_ERR_048, [colid, "[" + ds_copyTransWrkPlan.getCellData(i, colid) + "]"]);
                    ds_coshipping.setCellData(row, colid, ds_copyTransWrkPlan.getCellData(i, colid));
                    return;
                }
            } else {
                continue;
            }
        }
    }
};

scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tb_srchCond, [ica_srchFromDate, ica_srchToDate]);
};

scwin.f_MoveDown = async function() {
    let sumWtVal = sum_wt.getValue().replace(/,/g, "");
    if (parseFloat(sumWtVal) > 28000) {
        let chkConfirm = await $c.win.confirm("중량합계가 28TON을 초과하였습니다. 계속 진행하시겠습니까?");
        if (!chkConfirm) {
            return;
        }
    }
    let vCountRow = ds_transWrkPlan.getRowCount();

    if (vCountRow < 1) {
        await $c.win.alert("합적하실 운송물량을 먼저 조회해주십시오.");
        return false;
    } else {
        let coshippingNo = "";
        let cntSelectRow = 0;

        for (let i = 0; i < ds_transWrkIndict.getRowCount(); i++) {
            if (ds_transWrkIndict.getCellData(i, "chk") == "1" && ds_transWrkIndict.getRowStatus(i) != "D") {
                coshippingNo = ds_transWrkIndict.getCellData(i, "coshippingNo");
                cntSelectRow++;
            }
        }

        if (cntSelectRow > 1) {
            await $c.win.alert("선택된 합적연결물량이 2건이상입니다.  \n 신규 또는 한가지 물량에만 추가 합적할수 있습니다.");
            return;
        }

        for (let i = vCountRow - 1; i >= 0; i--) {
            let chkYn = ds_transWrkPlan.getCellData(i, "chk");

            if (chkYn == "T") {
                ds_transWrkPlan.setCellData(i, "chk", "F");

                if (parseFloat(ds_transWrkPlan.getCellData(i, "grossWt")) <= 0) {
                    continue;
                }

                let newRow = ds_transWrkIndict.insertRow();
                let colCount = ds_transWrkIndict.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkIndict.getColumnID(j);
                    let srcVal = ds_transWrkPlan.getCellData(i, vColid);
                    if (srcVal !== undefined && srcVal !== null) {
                        ds_transWrkIndict.setCellData(newRow, vColid, srcVal);
                    }
                }

                if (coshippingNo != "") {
                    ds_transWrkIndict.setCellData(newRow, "coshippingNo", coshippingNo);
                }

                scwin.qtyEventChk = true;
                ds_transWrkPlan.setCellData(i, "oldQty", parseFloat(ds_transWrkPlan.getCellData(i, "oldQty")) - parseFloat(ds_transWrkPlan.getCellData(i, "qty")));
                ds_transWrkPlan.setCellData(i, "qty", parseFloat(ds_transWrkPlan.getCellData(i, "oldQty")));
                ds_transWrkPlan.setCellData(i, "oldGrossWt", parseFloat(ds_transWrkPlan.getCellData(i, "oldGrossWt")) - parseFloat(ds_transWrkPlan.getCellData(i, "grossWt")));
                ds_transWrkPlan.setCellData(i, "grossWt", parseFloat(ds_transWrkPlan.getCellData(i, "oldGrossWt")));
                scwin.qtyEventChk = false;
            }
        }

        // TODO: HeadCheck reset - gr_transWrkPlan.ColumnProp("chk", "HeadCheck") = false equivalent
    }

    ds_transWrkIndict.sort("coshippingNo", "asc");
};

scwin.f_runExcel = function(gubun) {
    switch (gubun) {
        case 1:
            $c.data.downloadGridViewExcel(gr_transWrkPlan, { fileName: "운송물량.xlsx", sheetName: "합적연결등록" });
            break;
        case 2:
            $c.data.downloadGridViewExcel(gr_transWrkIndict, { fileName: "합적연결물량.xlsx", sheetName: "합적연결등록" });
            break;
    }
};

scwin.f_vehclNrm = async function() {
    await $c.sbm.execute(sbm_eqNrmCd);
};

scwin.f_CreatRoutingOrder = async function() {
    ds_transWrkRoutingPlan.removeAll();
    ds_transWrkRoutingPlanBefore.removeAll();
    ds_transWrkRoutingPlanAfter.removeAll();

    scwin.f_CopyDataSetHeader(ds_transWrkPlan, ds_transWrkRoutingPlan);
    scwin.f_CopyDataSetHeader(ds_transWrkPlan, ds_transWrkRoutingPlanBefore);
    scwin.f_CopyDataSetHeader(ds_transWrkPlan, ds_transWrkRoutingPlanAfter);

    let cntSelectRow = 0;
    let districtNm = "";
    let routingSeq = 0;
    let orgIndex = 0;
    let orgDate = "";
    let orgTime = 0;
    let orgGrossWt = 0;

    let eqNrmName = "";
    let eqNrmIdx = lc_eqNrmCd.getSelectedIndex();
    if (eqNrmIdx >= 0) {
        eqNrmName = ds_eqNrmCd.getCellData(eqNrmIdx, "name");
    }
    let VehcleCapa = parseFloat(eqNrmName.replace("TON", "")) * 1000 * 1.12;
    let totGrossWt = 0;

    for (let i = 0; i < ds_transWrkPlan.getRowCount(); i++) {
        if (ds_transWrkPlan.getCellData(i, "chk") == "T" && ds_transWrkPlan.getRowStatus(i) != "D") {
            districtNm = ds_transWrkPlan.getCellData(i, "districtNm");
            routingSeq = ds_transWrkPlan.getCellData(i, "routingSeq");

            orgDate = ds_transWrkPlan.getCellData(i, "wrkEndDt").substring(0, 8);
            orgTime = parseFloat(ds_transWrkPlan.getCellData(i, "wrkEndDt").substring(8, 10));

            orgGrossWt = parseFloat(ds_transWrkPlan.getCellData(i, "grossWt"));

            orgIndex = i;
            cntSelectRow++;
        }
    }

    if (cntSelectRow > 1) {
        await $c.win.alert("선택된 합적기준물량이 1건이상입니다.\n자동합적 기준물량을 1개만 선택해 주십시요.");
        return false;
    }

    for (let i = 0; i < ds_transWrkPlan.getRowCount(); i++) {
        if (orgDate == ds_transWrkPlan.getCellData(i, "wrkEndDt").substring(0, 8) &&
            districtNm == ds_transWrkPlan.getCellData(i, "districtNm") &&
            orgIndex != i) {

            if (parseFloat(ds_transWrkPlan.getCellData(i, "wrkEndDt").substring(8, 10)) <= orgTime) {
                let newRow = ds_transWrkRoutingPlanBefore.insertRow();
                let colCount = ds_transWrkPlan.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkPlan.getColumnID(j);
                    ds_transWrkRoutingPlanBefore.setCellData(newRow, vColid, ds_transWrkPlan.getCellData(i, vColid));
                }
                ds_transWrkRoutingPlanBefore.setCellData(newRow, "orgIndex", i);
            } else {
                let newRow = ds_transWrkRoutingPlanAfter.insertRow();
                let colCount = ds_transWrkPlan.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkPlan.getColumnID(j);
                    ds_transWrkRoutingPlanAfter.setCellData(newRow, vColid, ds_transWrkPlan.getCellData(i, vColid));
                }
                ds_transWrkRoutingPlanAfter.setCellData(newRow, "orgIndex", i);
            }
        }
    }

    ds_transWrkRoutingPlanBefore.sort("wrkEndDt", "desc");
    ds_transWrkRoutingPlanAfter.sort("wrkEndDt", "asc");

    let newRowOrg = ds_transWrkRoutingPlan.insertRow();
    let colCountOrg = ds_transWrkPlan.getColCount();
    for (let j = 0; j < colCountOrg; j++) {
        let vColid = ds_transWrkPlan.getColumnID(j);
        ds_transWrkRoutingPlan.setCellData(newRowOrg, vColid, ds_transWrkPlan.getCellData(orgIndex, vColid));
    }
    ds_transWrkRoutingPlan.setCellData(newRowOrg, "orgIndex", orgIndex);

    totGrossWt = orgGrossWt;

    let copyIndex = 1;
    let beforeIndex = 0;
    let afterIndex = 0;

    while (true) {
        if (ds_transWrkRoutingPlanBefore.getRowCount() <= beforeIndex && ds_transWrkRoutingPlanAfter.getRowCount() <= afterIndex) {
            break;
        }

        if (copyIndex % 2 == 1 &&
            ds_transWrkRoutingPlanBefore.getRowCount() > beforeIndex) {
            totGrossWt = totGrossWt + parseFloat(ds_transWrkRoutingPlanBefore.getCellData(beforeIndex, "grossWt"));
            if (totGrossWt <= VehcleCapa) {
                let newRow = ds_transWrkRoutingPlan.insertRow();
                let colCount = ds_transWrkRoutingPlanBefore.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkRoutingPlanBefore.getColumnID(j);
                    ds_transWrkRoutingPlan.setCellData(newRow, vColid, ds_transWrkRoutingPlanBefore.getCellData(beforeIndex, vColid));
                }
            }
            ++beforeIndex;
        } else if (copyIndex % 2 == 0 &&
            ds_transWrkRoutingPlanAfter.getRowCount() > afterIndex) {
            totGrossWt = totGrossWt + parseFloat(ds_transWrkRoutingPlanAfter.getCellData(afterIndex, "grossWt"));
            if (totGrossWt <= VehcleCapa) {
                let newRow = ds_transWrkRoutingPlan.insertRow();
                let colCount = ds_transWrkRoutingPlanAfter.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkRoutingPlanAfter.getColumnID(j);
                    ds_transWrkRoutingPlan.setCellData(newRow, vColid, ds_transWrkRoutingPlanAfter.getCellData(afterIndex, vColid));
                }
            }
            ++afterIndex;
        }

        ++copyIndex;
    }

    ds_transWrkRoutingPlan.sort("wrkEndDt", "asc");

    let prevWrkEndDt = parseFloat(ds_transWrkRoutingPlan.getCellData(0, "wrkEndDt").substring(8, 10));
    let timeSeq = 1;
    let stdTimeDiff = 1;

    ds_transWrkRoutingPlan.setCellData(0, "timeSeq", timeSeq);

    for (let i = 1; i < ds_transWrkRoutingPlan.getRowCount(); i++) {
        if (parseFloat(ds_transWrkRoutingPlan.getCellData(i, "wrkEndDt").substring(8, 10)) - prevWrkEndDt < stdTimeDiff) {
            ds_transWrkRoutingPlan.setCellData(i, "timeSeq", ds_transWrkRoutingPlan.getCellData(i - 1, "timeSeq"));
        } else {
            ds_transWrkRoutingPlan.setCellData(i, "timeSeq", ++timeSeq);
        }

        prevWrkEndDt = parseFloat(ds_transWrkRoutingPlan.getCellData(i, "wrkEndDt").substring(8, 10));
    }

    // TODO: multi-key sort "timeSeq asc, routingSeq asc" - WebSquare may need custom sort
    ds_transWrkRoutingPlan.sort("timeSeq", "asc");

    for (let i = 0; i < ds_transWrkRoutingPlan.getRowCount(); i++) {
        let orgIdx = parseInt(ds_transWrkRoutingPlan.getCellData(i, "orgIndex"));
        ds_transWrkPlan.setCellData(orgIdx, "chk", "T");
        ds_transWrkPlan.setCellData(orgIdx, "routingSeq", i + 1);
    }

    return true;
};

scwin.f_CopyDataSetHeader = function(oOriginDataSet, oTargetDataSet) {
    let colInfoArr = [];
    let colCount = oOriginDataSet.getColCount();

    for (let i = 0; i < colCount; i++) {
        let colId = oOriginDataSet.getColumnID(i);
        let colDataType = oOriginDataSet.getColumnDataType(i);
        colInfoArr.push({ id: colId, dataType: colDataType || "text" });
    }

    colInfoArr.push({ id: "orgIndex", dataType: "number" });
    colInfoArr.push({ id: "timeSeq", dataType: "number" });

    $c.data.createDataList(oTargetDataSet.getID(), colInfoArr);
};

scwin.f_AutoCoshipping = async function() {
    let result = await scwin.f_CreatRoutingOrder();
    if (!result) {
        return;
    }

    let coshippingNo = "";

    let eqNrmName = "";
    let eqNrmIdx = lc_eqNrmCd.getSelectedIndex();
    if (eqNrmIdx >= 0) {
        eqNrmName = ds_eqNrmCd.getCellData(eqNrmIdx, "name");
    }
    let VehcleCapa = parseFloat(eqNrmName.replace("TON", "")) * 1000 * 1.12;

    let sumWtVal = sum_wt.getValue().replace(/,/g, "");
    if (parseFloat(sumWtVal) > VehcleCapa) {
        let errText = "중량합계가 차량규격(" + eqNrmName + ")을 초과하였습니다. 계속 진행하시겠습니까?";
        let chkConfirm = await $c.win.confirm(errText);
        if (!chkConfirm) {
            return;
        }
    }

    let vCountRow = ds_transWrkPlan.getRowCount();

    if (vCountRow < 1) {
        await $c.win.alert("합적하실 운송물량을 먼저 조회해주십시오.");
        return false;
    } else {
        let cntSelectRow = 0;

        for (let i = 0; i < ds_transWrkIndict.getRowCount(); i++) {
            if (ds_transWrkIndict.getCellData(i, "chk") == "T" && ds_transWrkIndict.getRowStatus(i) != "D") {
                coshippingNo = ds_transWrkIndict.getCellData(i, "coshippingNo");
                cntSelectRow++;
            }
        }

        if (cntSelectRow > 1) {
            await $c.win.alert("선택된 합적연결물량이 2건이상입니다.\n신규 또는 한가지 물량에만 추가 합적할수 있습니다.");
            return;
        }

        for (let i = vCountRow - 1; i >= 0; i--) {
            let chkYn = ds_transWrkPlan.getCellData(i, "chk");

            if (chkYn == "T") {
                ds_transWrkPlan.setCellData(i, "chk", "F");

                if (parseFloat(ds_transWrkPlan.getCellData(i, "grossWt")) <= 0) {
                    continue;
                }

                let newRow = ds_transWrkIndict.insertRow();
                let colCount = ds_transWrkIndict.getColCount();
                for (let j = 0; j < colCount; j++) {
                    let vColid = ds_transWrkIndict.getColumnID(j);
                    let srcVal = ds_transWrkPlan.getCellData(i, vColid);
                    if (srcVal !== undefined && srcVal !== null) {
                        ds_transWrkIndict.setCellData(newRow, vColid, srcVal);
                    }
                }

                if (coshippingNo != "") {
                    ds_transWrkIndict.setCellData(newRow, "coshippingNo", coshippingNo);
                }

                scwin.qtyEventChk = true;
                ds_transWrkPlan.setCellData(i, "oldQty", parseFloat(ds_transWrkPlan.getCellData(i, "oldQty")) - parseFloat(ds_transWrkPlan.getCellData(i, "qty")));
                ds_transWrkPlan.setCellData(i, "qty", parseFloat(ds_transWrkPlan.getCellData(i, "oldQty")));
                ds_transWrkPlan.setCellData(i, "oldGrossWt", parseFloat(ds_transWrkPlan.getCellData(i, "oldGrossWt")) - parseFloat(ds_transWrkPlan.getCellData(i, "grossWt")));
                ds_transWrkPlan.setCellData(i, "grossWt", parseFloat(ds_transWrkPlan.getCellData(i, "oldGrossWt")));
                scwin.qtyEventChk = false;
            }
        }

        // TODO: HeadCheck reset
    }

    // TODO: multi-key sort "coshippingNo asc, routingSeq asc"
    ds_transWrkIndict.sort("coshippingNo", "asc");

    let routingSeqVal = 1;

    for (let k = 0; k < ds_transWrkIndict.getRowCount(); k++) {
        if (coshippingNo == ds_transWrkIndict.getCellData(k, "coshippingNo")) {
            ds_transWrkIndict.setCellData(k, "routingSeq", routingSeqVal);
            routingSeqVal++;
        }
    }
};

